const body = $json.body;
const vertical    = body.vertical;
const issue_type  = body.issue_type;

// SLA mapping per vertical + issue type
const SLA = {
  'Shop':          { 'Wrong Item': 48, 'Late Delivery': 72, 'Refund Request': 48, 'Other': 72 },
  'Meal Kits':     { 'Missing Ingredient': 24, 'Late Delivery': 24, 'Wrong Item': 24, 'Other': 48 },
  'Food Delivery': { 'Cold Food': 4, 'Late Delivery': 4, 'Wrong Item': 4, 'Other': 8 }
};

// AI suggested responses
const AI_RESPONSES = {
  'Wrong Item':         'Hi there, I\'m sorry you received the wrong item. I\'ve raised a replacement — it will arrive within the SLA window. No need to return the incorrect item.',
  'Missing Ingredient': 'Hi there, I\'m sorry about the missing ingredient in your meal kit. I\'ve arranged a full refund for the affected portion within 3–5 business days.',
  'Cold Food':          'Hi there, I\'m sorry your food arrived cold. I\'ve issued a full refund which will appear within 24 hours.',
  'Late Delivery':      'Hi there, I apologise for the delay. I\'ve applied a delivery credit to your account as a goodwill gesture.',
  'Refund Request':     'Hi there, I\'ve reviewed and approved your refund request. You\'ll see the amount within 3–5 business days.',
  'Other':              'Hi there, thank you for reaching out. I\'m reviewing your case and will update you shortly.'
};

// Resolution flow per vertical
const RESOLUTION_FLOWS = {
  'Shop':          'shop_returns_flow',
  'Meal Kits':     'meal_kit_missing_ingredient_flow',
  'Food Delivery': 'food_delivery_dispute_flow'
};

const sla_hours       = SLA[vertical]?.[issue_type] || SLA[vertical]?.['Other'] || 48;
const ai_response     = AI_RESPONSES[issue_type] || AI_RESPONSES['Other'];
const resolution_flow = RESOLUTION_FLOWS[vertical] || 'generic_support_flow';

return [{
  json: {
    customer_email:       body.customer_email,
    vertical,
    issue_type,
    status:               'Open',
    sla_hours,
    ai_suggested_response: ai_response,
    resolution_flow,
    raw: body
  }
}];
